package com.careeros.documents.infrastructure;import com.careeros.documents.application.PdfConverter;import org.springframework.stereotype.Component;import java.nio.file.*;import java.util.*;@Component public class LibreOfficePdfAdapter implements PdfConverter{private final ProcessRunner runner;private final ResumeDocumentProperties p;public LibreOfficePdfAdapter(ProcessRunner r,ResumeDocumentProperties p){runner=r;this.p=p;}public Path convert(Path docx,Path output){String binary=find();runner.run(List.of(binary,"--headless","--convert-to","pdf","--outdir",output.toString(),docx.toString()),null,p.processTimeout());Path pdf=output.resolve(strip(docx.getFileName().toString())+".pdf");if(!Files.isRegularFile(pdf))throw new IllegalStateException("LibreOffice completed without creating "+pdf);return pdf;}private String find(){if(p.libreOfficePath()!=null&&!p.libreOfficePath().isBlank())return p.libreOfficePath();for(String candidate:List.of("soffice","libreoffice","/Applications/LibreOffice.app/Contents/MacOS/soffice")){if(candidate.startsWith("/")&&Files.isExecutable(Path.of(candidate)))return candidate;if(!candidate.startsWith("/")&&onPath(candidate))return candidate;}throw new IllegalStateException("LibreOffice not found; configure LIBREOFFICE_PATH");}private boolean onPath(String name){for(String d:System.getenv().getOrDefault("PATH","").split(java.io.File.pathSeparator))if(Files.isExecutable(Path.of(d,name)))return true;return false;}private String strip(String n){int i=n.lastIndexOf('.');return i<0?n:n.substring(0,i);}}
